const url = $input.first().json.body.url;

// Use regex to extract the place name after '/place/' and before the next '/'
const match = url.match(/\/place\/([^\/]+)\//);

const placeName = match ? decodeURIComponent(match[1].replace(/\+/g, ' ')) : null;

// Return result
return [
  {
    json: {
      placeName
    }
  }
];

