const url = $input.first().json.body.url;

// Remove query params
const cleanUrl = url.split("?")[0];

// Split into parts
const parts = cleanUrl.split("/");

// Find "dp" index (this appears in all Amazon product URLs)
const dpIndex = parts.indexOf("dp");

// If dp exists, the product name is the segment before it
let productName = "";
if (dpIndex > 0) {
    productName = parts[dpIndex - 1];
}

// Replace dashes with spaces for readability
const readableName = productName.replace(/-/g, " ");
// Extract ASIN
let asin = "";
const asinMatch = url.match(/\/dp\/([A-Z0-9]{10})/) || url.match(/\/product\/([A-Z0-9]{10})/);
if (asinMatch) asin = asinMatch[1];

// Extract Amazon domain
const domainMatch = url.match(/amazon\.(in|com|co\.uk|ca|de|fr|ae)/i);
const amazonDomain = domainMatch ? `amazon.${domainMatch[1]}` : "amazon.com";

// Return both raw + readable
return [
    {
        json: {
            product_name_raw: productName,
            product_name: readableName,
            asin,
            amazonDomain
        }
    }
];

// --- STEP 1: Extract input ---
let input = $input.all()[0].json;

// If input is wrapped inside an array, unwrap first element
if (Array.isArray(input)) {
    input = input[0];
}

// --- STEP 2: Get author reviews array ---
const authorReviewsArray = input.reviews_information && input.reviews_information.authors_reviews
    ? input.reviews_information.authors_reviews
    : [];

// --- STEP 3: Sort by date (newest first) ---
const sorted = authorReviewsArray.sort((a, b) => {
    if (a.date && b.date) {
        return new Date(b.date) - new Date(a.date);
    }
    return 0;
});

// --- STEP 4: Take latest 10 reviews ---
const latest10 = sorted.slice(0, 10);

// --- STEP 5: Extract text from each review ---
const reviewsarray = latest10.map(r => r.text || "").filter(t => t.trim() !== "");

// --- STEP 6: Prepare individual array for Telegram ---
const telegramArray = latest10.map((r, index) => ({
    review_number: index + 1,
    author: r.author,
    rating: r.rating,
    date: r.date,
    text: r.text
}));

// --- STEP 7: Return as a single item containing arrays ---
return [
    {
        json: {
            reviewsarray: reviewsarray,
            // reviews_for_telegram: telegramArray
        }
    }
];

// Get AI output from previous node
const text = $input.first().json.output || "";
// Split by two or more newlines to separate model blocks
const modelBlocks = text.split(/\n\s*\n+/).filter(Boolean);

// Build a plain JS array
const models = modelBlocks.map(block => {
    const lines = block.split('\n').map(l => l.trim()).filter(Boolean);

    return {
        model: lines[0] || 'Unknown',
        positive: Number(lines[1]?.match(/Positive:\s*(\d+(?:\.\d+)?)%/i)?.[1] || 0),
        negative: Number(lines[2]?.match(/Negative:\s*(\d+(?:\.\d+)?)%/i)?.[1] || 0),
        neutral:  Number(lines[3]?.match(/Neutral:\s*(\d+(?:\.\d+)?)%/i)?.[1] || 0)
    };
});

// ✅ Return ONE n8n item with an array inside
return [
  {
    json: {
      models
    }
  }
];
